    #[test]
    fn propagate_dirty_component_members_tracks_resolved_members_within_component() {
        let dependencies = BTreeMap::from([(1, vec![]), (2, vec![1]), (3, vec![2])]);
        let ordered_components = vec![vec![1, 2], vec![3]];
        let roots = BTreeSet::from([1]);
        let mut seen_resolved = Vec::new();

        let changed = propagate_dirty_component_members(
            &roots,
            &ordered_components,
            &dependencies,
            |member, _component_set, resolved_in_component| {
                seen_resolved.push((
                    member,
                    resolved_in_component.iter().copied().collect::<Vec<_>>(),
                ));
                Ok::<_, ()>(member == 1)
            },
        )
        .expect("propagation succeeds");

        assert_eq!(seen_resolved, vec![(1, vec![]), (2, vec![1])]);
        assert_eq!(changed, BTreeSet::from([1]));
    }

    #[test]
    fn propagate_dirty_component_members_with_scratch_clears_changed_nodes_between_calls() {
        let dependencies = BTreeMap::from([(1, vec![]), (2, vec![1]), (3, vec![2])]);
        let ordered_components = vec![vec![1], vec![2], vec![3]];
        let roots = BTreeSet::from([1]);
        let mut scratch = DirtyComponentMembersScratch::default();
        let mut first_visited = Vec::new();

        propagate_dirty_component_members_with_scratch(
            &roots,
            &ordered_components,
            &dependencies,
            &mut scratch,
            |member, _component_set, _resolved_in_component| {
                first_visited.push(member);
                Ok::<_, ()>(member == 1)
            },
        )
        .expect("first propagation succeeds");

        assert_eq!(first_visited, vec![1, 2]);
        assert_eq!(scratch.changed_nodes, BTreeSet::from([1]));

        let mut second_visited = Vec::new();
        propagate_dirty_component_members_with_scratch(
            &roots,
            &ordered_components,
            &dependencies,
            &mut scratch,
            |member, _component_set, _resolved_in_component| {
                second_visited.push(member);
                Ok::<_, ()>(false)
            },
        )
        .expect("second propagation succeeds");

        assert_eq!(second_visited, vec![1]);
        assert!(scratch.changed_nodes.is_empty());
    }

    #[test]
    fn apply_dependency_member_uses_resolved_component_values_and_tracks_change() {
        let mut values = BTreeMap::from([(1, 5i64)]);
        let mut output_seqs = BTreeMap::from([(1, CausalSeq::new(1, 0))]);
        let unresolved = PropagatedValue {
            value: 0i64,
            seq: CausalSeq::new(0, 0),
        };

        let changed = apply_dependency_member(
            2,
            &[1, 2],
            &HashSet::from([1, 2]),
            &HashSet::from([1]),
            &mut values,
            &mut output_seqs,
            &unresolved,
            |inputs| {
                assert_eq!(
                    inputs,
                    &[
                        PropagatedValue {
                            value: 5,
                            seq: CausalSeq::new(1, 0),
                        },
                        PropagatedValue {
                            value: 0,
                            seq: CausalSeq::new(0, 0),
                        },
                    ]
                );
                Ok::<_, ()>(PropagatedValue {
                    value: 5,
                    seq: CausalSeq::new(1, 0),
                })
            },
        )
        .expect("evaluation succeeds");

        assert!(changed);
        assert_eq!(values.get(&2), Some(&5));
        assert_eq!(output_seqs.get(&2), Some(&CausalSeq::new(1, 0)));
    }

    #[test]
    fn apply_dependency_member_does_not_regress_existing_output_seq() {
        let mut values = BTreeMap::from([(2, 5i64)]);
        let mut output_seqs = BTreeMap::from([(2, CausalSeq::new(5, 0))]);
        let unresolved = PropagatedValue {
            value: 0i64,
            seq: CausalSeq::new(0, 0),
        };

        let changed = apply_dependency_member(
            2,
            &[],
            &HashSet::new(),
            &HashSet::new(),
            &mut values,
            &mut output_seqs,
            &unresolved,
            |_| {
                Ok::<_, ()>(PropagatedValue {
                    value: 5,
                    seq: CausalSeq::new(3, 0),
                })
            },
        )
        .expect("evaluation succeeds");

        assert!(!changed);
        assert_eq!(values.get(&2), Some(&5));
        assert_eq!(output_seqs.get(&2), Some(&CausalSeq::new(5, 0)));
    }

