    #[test]
    fn retained_evaluator_rejects_stale_source_pulse_by_slot_cutoff() {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SourcePort(SourcePortId(30)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Literal(KernelValue::from(1.0)),
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Then {
                    source: NodeId(1),
                    body: NodeId(2),
                },
            },
            crate::ir::IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MathSum { input: NodeId(3) },
            },
            crate::ir::IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(30),
                    input: NodeId(4),
                },
            },
        ]);
        let mut evaluator =
            RetainedMirrorEvaluator::new(program, SinkPortId(30), vec![]).expect("evaluator");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        evaluator
            .executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("pulse"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("fresh pulse executes");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from(1.0)));

        evaluator
            .executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("stale"),
                    seq: CausalSeq::new(1, 9),
                },
            )])
            .expect("stale pulse is ignored");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from(1.0)));

        evaluator
            .executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("fresh-again"),
                    seq: CausalSeq::new(2, 1),
                },
            )])
            .expect("newer pulse executes");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from(2.0)));
    }

