    #[test]
    fn retained_evaluator_fresh_mirror_snapshot_only_resets_targeted_cutoffs() {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(60)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(61)),
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(60),
                    input: NodeId(1),
                },
            },
            crate::ir::IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(61),
                    input: NodeId(2),
                },
            },
        ]);
        let mut evaluator = RetainedMirrorEvaluator::new(
            program,
            SinkPortId(60),
            vec![MirrorCellId(60), MirrorCellId(61)],
        )
        .expect("evaluator");

        evaluator
            .apply_mirror_write(
                MirrorCellId(60),
                KernelValue::from("fresh-a"),
                CausalSeq::new(5, 0),
            )
            .expect("initial first mirror write applies");
        evaluator
            .apply_mirror_write(
                MirrorCellId(61),
                KernelValue::from("fresh-b"),
                CausalSeq::new(6, 0),
            )
            .expect("initial mirror writes apply");

        evaluator
            .executor
            .apply_mirror_writes_with_fresh_cells(
                [
                    (
                        MirrorCellId(60),
                        KernelValue::from("replayed-a"),
                        CausalSeq::new(3, 0),
                    ),
                    (
                        MirrorCellId(61),
                        KernelValue::from("stale-b"),
                        CausalSeq::new(4, 0),
                    ),
                ],
                &[MirrorCellId(60)],
            )
            .expect("targeted fresh snapshot applies only for requested mirror");

        assert_eq!(
            evaluator.executor.sink_value(SinkPortId(60)),
            Some(&KernelValue::from("replayed-a"))
        );
        assert_eq!(
            evaluator.executor.sink_value(SinkPortId(61)),
            Some(&KernelValue::from("fresh-b"))
        );
    }

    #[test]
    fn retained_evaluator_list_get_same_selected_item_update_advances_sink_control_seq() {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(70)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Literal(KernelValue::from(2.0)),
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::ListGet {
                    list: NodeId(1),
                    index: NodeId(2),
                },
            },
            crate::ir::IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(70),
                    input: NodeId(3),
                },
            },
        ]);
        let mut evaluator =
            RetainedMirrorEvaluator::new(program, SinkPortId(70), vec![MirrorCellId(70)])
                .expect("evaluator");

        evaluator
            .apply_mirror_write(
                MirrorCellId(70),
                KernelValue::List(vec![
                    KernelValue::from("left"),
                    KernelValue::from("selected"),
                ]),
                CausalSeq::new(1, 0),
            )
            .expect("initial list-get write is accepted");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("selected")));

        let before_get = evaluator.executor.evaluation_count(NodeId(3));
        let before_sink = evaluator.executor.evaluation_count(NodeId(4));

        evaluator
            .apply_mirror_write(
                MirrorCellId(70),
                KernelValue::List(vec![
                    KernelValue::from("changed"),
                    KernelValue::from("selected"),
                ]),
                CausalSeq::new(2, 0),
            )
            .expect("same selected list-get write is accepted");

        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("selected")));
        assert_eq!(evaluator.sink_seq(), Some(CausalSeq::new(2, 0)));
        assert!(evaluator.executor.evaluation_count(NodeId(3)) > before_get);
        assert!(evaluator.executor.evaluation_count(NodeId(4)) > before_sink);
    }

