    #[test]
    fn retained_evaluator_list_count_same_length_update_revisits_then_through_eq_control_dependent()
    {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(73)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::ListCount { list: NodeId(1) },
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Literal(KernelValue::from(2.0)),
            },
            crate::ir::IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Eq {
                    lhs: NodeId(2),
                    rhs: NodeId(3),
                },
            },
            crate::ir::IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Literal(KernelValue::from("selected")),
            },
            crate::ir::IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(5),
                },
            },
            crate::ir::IrNode {
                id: NodeId(7),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(73),
                    input: NodeId(6),
                },
            },
        ]);
        let mut evaluator =
            RetainedMirrorEvaluator::new(program, SinkPortId(73), vec![MirrorCellId(73)])
                .expect("evaluator");

        evaluator
            .apply_mirror_write(
                MirrorCellId(73),
                KernelValue::List(vec![KernelValue::from(1.0), KernelValue::from(2.0)]),
                CausalSeq::new(1, 0),
            )
            .expect("initial list count eq->then write is accepted");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("selected")));

        let before_count = evaluator.executor.evaluation_count(NodeId(2));
        let before_eq = evaluator.executor.evaluation_count(NodeId(4));
        let before_then = evaluator.executor.evaluation_count(NodeId(6));
        let before_sink = evaluator.executor.evaluation_count(NodeId(7));

        evaluator
            .apply_mirror_write(
                MirrorCellId(73),
                KernelValue::List(vec![KernelValue::from(7.0), KernelValue::from(8.0)]),
                CausalSeq::new(2, 0),
            )
            .expect("same-length list count eq->then write is accepted");

        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("selected")));
        assert_eq!(evaluator.sink_seq(), Some(CausalSeq::new(2, 0)));
        assert!(evaluator.executor.evaluation_count(NodeId(2)) > before_count);
        assert!(evaluator.executor.evaluation_count(NodeId(4)) > before_eq);
        assert!(evaluator.executor.evaluation_count(NodeId(6)) > before_then);
        assert!(evaluator.executor.evaluation_count(NodeId(7)) > before_sink);
    }

