        assert_eq!(evaluator.sink_seq(), Some(CausalSeq::new(1, 0)));

        let before_map = evaluator.executor.evaluation_count(NodeId(4));
        let before_get = evaluator.executor.evaluation_count(NodeId(6));
        let before_then = evaluator.executor.evaluation_count(NodeId(8));
