    #[test]
    fn retained_evaluator_field_read_same_value_update_advances_sink_control_seq() {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(78)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::FieldRead {
                    object: NodeId(1),
                    field: "title".to_string(),
                },
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(78),
                    input: NodeId(2),
                },
            },
        ]);
        let mut evaluator =
            RetainedMirrorEvaluator::new(program, SinkPortId(78), vec![MirrorCellId(78)])
                .expect("evaluator");

        let object = KernelValue::Object(std::collections::BTreeMap::from([
            ("done".to_string(), KernelValue::from(false)),
            ("title".to_string(), KernelValue::from("todo")),
        ]));

        evaluator
            .apply_mirror_write(MirrorCellId(78), object.clone(), CausalSeq::new(1, 0))
            .expect("initial field-read write is accepted");
        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("todo")));

        let before_read = evaluator.executor.evaluation_count(NodeId(2));
        let before_sink = evaluator.executor.evaluation_count(NodeId(3));

        evaluator
            .apply_mirror_write(MirrorCellId(78), object, CausalSeq::new(2, 0))
            .expect("same-value newer-seq field-read write is accepted");

        assert_eq!(evaluator.sink_value(), Some(&KernelValue::from("todo")));
        assert_eq!(evaluator.sink_seq(), Some(CausalSeq::new(2, 0)));
        assert!(evaluator.executor.evaluation_count(NodeId(2)) > before_read);
        assert!(evaluator.executor.evaluation_count(NodeId(3)) > before_sink);
    }

