    #[test]
    fn retained_evaluator_object_literal_same_field_update_advances_sink_control_seq() {
        let program = IrProgram::from(vec![
            crate::ir::IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(88)),
            },
            crate::ir::IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: crate::ir::IrNodeKind::Literal(KernelValue::from(false)),
            },
            crate::ir::IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: crate::ir::IrNodeKind::ObjectLiteral {
                    fields: vec![
                        ("title".to_string(), NodeId(1)),
                        ("done".to_string(), NodeId(2)),
                    ],
                },
            },
            crate::ir::IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: crate::ir::IrNodeKind::SinkPort {
                    port: SinkPortId(88),
                    input: NodeId(3),
                },
            },
        ]);
        let mut evaluator =
            RetainedMirrorEvaluator::new(program, SinkPortId(88), vec![MirrorCellId(88)])
                .expect("evaluator");

        let expected = KernelValue::Object(std::collections::BTreeMap::from([
            ("done".to_string(), KernelValue::from(false)),
            ("title".to_string(), KernelValue::from("todo")),
        ]));

        evaluator
            .apply_mirror_write(
                MirrorCellId(88),
                KernelValue::from("todo"),
                CausalSeq::new(1, 0),
            )
            .expect("initial object-literal write is accepted");
        assert_eq!(evaluator.sink_value(), Some(&expected));

        let before_object = evaluator.executor.evaluation_count(NodeId(3));
        let before_sink = evaluator.executor.evaluation_count(NodeId(4));

        evaluator
            .apply_mirror_write(
                MirrorCellId(88),
                KernelValue::from("todo"),
                CausalSeq::new(2, 0),
            )
            .expect("same object-literal field write is accepted");

        assert_eq!(evaluator.sink_value(), Some(&expected));
        assert_eq!(evaluator.sink_seq(), Some(CausalSeq::new(2, 0)));
        assert!(evaluator.executor.evaluation_count(NodeId(3)) > before_object);
        assert!(evaluator.executor.evaluation_count(NodeId(4)) > before_sink);
    }

