    #[test]
    fn replace_retained_member_program_preserves_downstream_member_instance_id_after_recompute() {
        let mut leaf = RetainedMirrorEvaluator::new(
            IrProgram::from(vec![
                crate::ir::IrNode {
                    id: NodeId(1),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(10)),
                },
                crate::ir::IrNode {
                    id: NodeId(2),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::SinkPort {
                        port: SinkPortId(1),
                        input: NodeId(1),
                    },
                },
            ]),
            SinkPortId(1),
            vec![MirrorCellId(10)],
        )
        .expect("leaf evaluator");
        leaf.apply_mirror_write(
            MirrorCellId(10),
            KernelValue::from(5.0),
            CausalSeq::new(3, 0),
        )
        .expect("seed leaf");

        let add = RetainedMirrorEvaluator::new(
            IrProgram::from(vec![
                crate::ir::IrNode {
                    id: NodeId(1),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(20)),
                },
                crate::ir::IrNode {
                    id: NodeId(2),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(21)),
                },
                crate::ir::IrNode {
                    id: NodeId(3),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::Add {
                        lhs: NodeId(1),
                        rhs: NodeId(2),
                    },
                },
                crate::ir::IrNode {
                    id: NodeId(4),
                    source_expr: None,
                    kind: crate::ir::IrNodeKind::SinkPort {
                        port: SinkPortId(2),
                        input: NodeId(3),
                    },
                },
            ]),
            SinkPortId(2),
            vec![MirrorCellId(20), MirrorCellId(21)],
        )
        .expect("add evaluator");

        let mut retained = RetainedMemberRuntime::<u32> {
            evaluators: BTreeMap::from([(1, leaf), (2, add)]),
            mirror_cells: BTreeMap::from([(1, MirrorCellId(10))]),
            input_values: BTreeMap::from([(1, KernelValue::from(5.0))]),
            input_seqs: BTreeMap::from([(1, CausalSeq::new(3, 0))]),
            output_seqs: BTreeMap::new(),
            instance_ids: BTreeMap::from([(1, 41), (2, 73)]),
            #[cfg(test)]
            evaluation_counts: BTreeMap::new(),
            next_seq: 3,
            next_instance_id: 120,
            dirty_component_members_scratch: DirtyComponentMembersScratch::default(),
            number_dependency_input_scratch: Vec::new(),
        };

        replace_retained_member_program(
            &mut retained,
            1,
            Some(RetainedMemberProgram {
                member: 1,
                program: IrProgram::from(vec![
                    crate::ir::IrNode {
                        id: NodeId(1),
                        source_expr: None,
                        kind: crate::ir::IrNodeKind::MirrorCell(MirrorCellId(10)),
                    },
                    crate::ir::IrNode {
                        id: NodeId(2),
                        source_expr: None,
                        kind: crate::ir::IrNodeKind::Block {
                            inputs: vec![NodeId(1)],
                        },
                    },
                    crate::ir::IrNode {
                        id: NodeId(3),
                        source_expr: None,
                        kind: crate::ir::IrNodeKind::SinkPort {
                            port: SinkPortId(1),
                            input: NodeId(2),
                        },
                    },
                ]),
                sink_port: SinkPortId(1),
                dependency_mirrors: vec![MirrorCellId(10)],
                mirror_cell: Some(MirrorCellId(10)),
                fallback_input_value: Some(KernelValue::from(9.0)),
            }),
        )
        .expect("replace succeeds");

        let dependencies = BTreeMap::from([(1, vec![]), (2, vec![1, 1])]);
        let ordered_components = vec![vec![1], vec![2]];
        let roots = BTreeSet::from([1]);
        let mut values = BTreeMap::from([(2, 10)]);

        recompute_retained_members(
            &roots,
            &ordered_components,
            &dependencies,
            &mut retained,
            &mut values,
            PropagatedValue {
                value: 0i64,
                seq: CausalSeq::new(0, 0),
            },
            |member, evaluator, dependency_inputs, input_seq| {
                let _ = member;
                evaluate_retained_member(
                    evaluator,
                    dependency_inputs,
                    input_seq,
                    |value| KernelValue::from(*value as f64),
                    |retained_evaluator| match retained_evaluator.sink_value() {
                        Some(KernelValue::Number(value)) => *value as i64,
                        _ => 0,
                    },
                )
            },
        )
        .expect("recompute succeeds");

        assert_eq!(values.get(&1), Some(&5));
        assert_eq!(values.get(&2), Some(&10));
        assert_eq!(retained.instance_ids.get(&1), Some(&41));
        assert_eq!(retained.instance_ids.get(&2), Some(&73));
        assert_eq!(retained.next_instance_id, 120);
    }

